#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define fr first
#define se second
#define pb push_back
using namespace std;
string L,R;
LL n,ch,Ans,dp[20][2][2][10];
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}

int main(){
    cin>>L>>R;
    n=R.size(),ch=n-L.size();
    while(L.size()<n)L="0"+L;
    dp[0][0][0][0]=1;
    for(int i=0;i<n;i++)for(int x=0;x<2;x++)
    for(int y=0;y<2;y++)for(int j=0;j<=9;j++)
        for(int k=(x?0:(L[i]-'0'));k<=(y?9:(R[i]-'0'));k++){
            int nx=(x||k>(L[i]-'0')),ny=(y||k<(R[i]-'0'));
            if((!x&&i<=ch)||abs(j-k)>1)dp[i+1][nx][ny][k]+=dp[i][x][y][j];
        }
    for(int x=0;x<2;x++)for(int y=0;y<2;y++)
        for(int i=0;i<10;i++)Ans+=dp[n][x][y][i];
    cout<<Ans<<"\n";
    return 0;
}
